FUNCTION factorial(n):
 IF n <= 1 THEN
 RETURN 1
 ELSE
 RETURN n * factorial(n-1)
 END IF
END FUNCTION

// Proof by induction:
// Base: factorial(1) = 1 = 1!
// Inductive: Assume factorial(k) = k!
// Then factorial(k+1) = (k+1) * factorial(k) = (k+1) * k! = (k+1)!

// Fibonacci: F(1)=1, F(2)=1, F(n)=F(n-1)+F(n-2)

FUNCTION prove_fib_property(n):
 // Claim: F(n+1) * F(n-1) - F(n)² = (-1)ⁿ
 // This is Cassini's identity

 // Base cases:
 // n=1: F(2)*F(0) - F(1)² = 1*1 - 1*1 = 0 = (-1)¹ ✓
 // n=2: F(3)*F(1) - F(2)² = 2*1 - 1*1 = 1 = (-1)² ✓

 // Inductive step (strong induction):
 // Assume true for all k ≤ n
 // Prove for n+1:
 // F(n+2)F(n) - F(n+1)²
 // = (F(n+1)+F(n))F(n) - F(n+1)²
 // = F(n+1)F(n) + F(n)² - F(n+1)²
 // = -(F(n+1)F(n-1) - F(n)²)
 // = -((-1)ⁿ) = (-1)ⁿ⁺¹ ✓

FUNCTION power_product_proof(a, b, n):
 // Claim: (ab)ⁿ = aⁿ * bⁿ for all n ≥ 1

 // Base case n=1:
 // (ab)¹ = ab = a¹ * b¹ ✓

 // Inductive step:
 // Assume (ab)ᵏ = aᵏ * bᵏ
 // Prove (ab)ᵏ⁺¹ = aᵏ⁺¹ * bᵏ⁺¹

